        test_cases=[{'input': ['Merhaba', 'Araba'], 'expected': ['a', 'r']}, {'input': ['Python', 'Java'], 'expected': ['a']}, {'input': ['abc', 'def'], 'expected': []}, {'input': ['AAA', 'aaa'], 'expected': ['a']}],
